import time

tasks = []
next_id = 1

def add_task(name, priority, due_timestamp):
    global next_id
    task = {
        'id': next_id,
        'name': name,
        'priority': priority,
        'due': due_timestamp,
        'completed': False,
        'created': time.time()
    }
    next_id = next_id + 1
    tasks.append(task)
    return task['id']

def complete_task(task_id):
    for t in tasks:
        if t['id'] == task_id:
            t['completed'] = True
            return True
    return False

def get_pending():
    pending = []
    for t in tasks:
        if t['completed'] == False:
            pending.append(t)
    result = []
    for t in pending:
        result.append(t)
    # Sort by priority (higher first) then by due date
    for i in range(len(result)):
        for j in range(i + 1, len(result)):
            if result[j]['priority'] > result[i]['priority']:
                temp = result[i]
                result[i] = result[j]
                result[j] = temp
            elif result[j]['priority'] == result[i]['priority']:
                if result[j]['due'] < result[i]['due']:
                    temp = result[i]
                    result[i] = result[j]
                    result[j] = temp
    return result

def get_overdue():
    now = time.time()
    overdue = []
    for t in tasks:
        if t['completed'] == False and t['due'] < now:
            overdue.append(t)
    return overdue

def delete_task(task_id):
    global tasks
    new_tasks = []
    for t in tasks:
        if t['id'] != task_id:
            new_tasks.append(t)
    tasks = new_tasks

def get_stats():
    total = len(tasks)
    completed = 0
    pending = 0
    for t in tasks:
        if t['completed']:
            completed = completed + 1
        else:
            pending = pending + 1
    return {'total': total, 'completed': completed, 'pending': pending}
